setTimeout(() => {
  const proyectados = parseFloat(this.frm_cot_ingresos_proyectados_anuales) || 0;
  const operaciones = parseFloat(this.frm_cot_ingresos_operaciones_anuales) || 0;

  const inputProyectados = document.querySelector('input[name="frm_cot_ingresos_proyectados_anuales"]');
  const contenedorFormGroup = inputProyectados?.closest('.form-group');

  const maximoPermitido = operaciones * 1.20;

  if (proyectados > maximoPermitido && operaciones > 0) {
    if (inputProyectados && !inputProyectados.classList.contains('is-invalid')) {
      inputProyectados.classList.add('is-invalid');
    }

    if (contenedorFormGroup && !contenedorFormGroup.querySelector('.invalid-feedback')) {
      const errorDiv = document.createElement('div');
      errorDiv.className = 'invalid-feedback d-block';
      errorDiv.innerHTML = '<div>Los ingresos proyectados no deben superar el 20% de los ingresos operacionales anuales.</div>';
      contenedorFormGroup.insertBefore(errorDiv, contenedorFormGroup.querySelector('small.form-text'));
    }

    const boton = document.querySelector('[custom-css-selector="btn_preventivo_proyectadoAnual"]');
    if (boton && boton.__vue__) {
      boton.__vue__.$root.$bvModal.show('modal_ingresos_incorrectos');
    }
  } else {
    if (inputProyectados?.classList.contains('is-invalid')) {
      inputProyectados.classList.remove('is-invalid');
    }

    if (contenedorFormGroup) {
      const mensajeError = contenedorFormGroup.querySelector('.invalid-feedback');
      if (mensajeError) mensajeError.remove();
    }
  }
}, 600);

const proyectados = parseFloat(this.frm_cot_ingresos_proyectados_anuales) || 0;
const operaciones = parseFloat(this.frm_cot_ingresos_operaciones_anuales) || 0;
const maximoPermitido = operaciones * 0.20;

if (proyectados > maximoPermitido && operaciones > 0) {
  return null;
}

return this.frm_cot_ingresos_proyectados_anuales;

const inicio = this.frm_cot_fecha_inicio_vigencia;
const minima = this.frm_cot_fecha_inicio_vigencia_minima;

if (!inicio || !minima) return inicio;

const inicioDate = new Date(`${inicio}T00:00:00`);
const minimaDate = new Date(`${minima}T00:00:00`);

const MS_PER_DAY = 24 * 60 * 60 * 1000;
const diffDays = Math.floor((inicioDate - minimaDate) / MS_PER_DAY);

const inputFecha = document.querySelector('input[name="frm_cot_fecha_inicio_vigencia"]');
const contenedorFormGroup = inputFecha?.closest('.form-group');

if (diffDays > 30) {
  if (inputFecha && !inputFecha.classList.contains('is-invalid')) {
    inputFecha.classList.add('is-invalid');
  }

  if (contenedorFormGroup && !contenedorFormGroup.querySelector('.invalid-feedback')) {
    const errorDiv = document.createElement('div');
    errorDiv.className = 'invalid-feedback d-block';
    errorDiv.innerHTML = '<div>Debe ser igual a fecha de hoy o máximo 30 días</div>';
    contenedorFormGroup.insertBefore(errorDiv, contenedorFormGroup.querySelector('small.form-text'));
  }

  setTimeout(() => {
    const modalComponent = document.querySelector('[custom-css-selector="btn_preventivo"]');
    if (!modalComponent || !modalComponent.__vue__) return;

    const vueInstance = modalComponent.__vue__;
    vueInstance.$root.$bvModal.show('modal_fecha_invalida');
  }, 300);

  return null;
}

if (inputFecha && inputFecha.classList.contains('is-invalid')) {
  inputFecha.classList.remove('is-invalid');
}

if (contenedorFormGroup) {
  const mensajeError = contenedorFormGroup.querySelector('.invalid-feedback');
  if (mensajeError) mensajeError.remove();
}

return this.frm_cot_fecha_inicio_vigencia;

const fechaCot = this.frm_cot_fecha_inicio_vigencia_minima;
if (!fechaCot) return null; 

const fecha = new Date(`${fechaCot}T00:00:00`);

fecha.setDate(fecha.getDate() + 30);

return fecha.toISOString().slice(0, 10);

const inicioStr = this.frm_cot_fecha_inicio_vigencia; 
const periodicidad = this.frm_cot_periodicidad;      

if (!inicioStr || !periodicidad) return null;

let totalDias = 0;

if (periodicidad === "ANUAL") {

  totalDias = 365;
} else if (periodicidad === "OTRA") {
  const meses = Number(this.frm_cot_num_meses || 0);
  if (!meses || meses <= 0) return null;


  totalDias = meses * 30;
} else {

  return null;
}


const fecha = new Date(`${inicioStr}T00:00:00`);
fecha.setDate(fecha.getDate() + totalDias);


return fecha.toISOString().slice(0, 10);

const iniStr = this.frm_cot_fecha_inicio_vigencia; 
const finStr = this.frm_cot_fecha_fin_vigencia;    

if (!iniStr || !finStr) return null;

const [y1, m1, d1] = iniStr.split('-').map(Number);
const [y2, m2, d2] = finStr.split('-').map(Number);

const t1 = Date.UTC(y1, (m1 || 1) - 1, d1 || 1);
const t2 = Date.UTC(y2, (m2 || 1) - 1, d2 || 1);

const MS_PER_DAY = 24 * 60 * 60 * 1000;

const diffDays = Math.floor((t2 - t1) / MS_PER_DAY);

return diffDays;

const finStr = this.frm_cot_fecha_fin_vigencia_editable;
const minStr = this.frm_cot_fecha_inicio_vigencia;

