/* ===== FILE DOWNLOAD – dashed #DEE2E6 + hover azul/gris ===== */
[selector="file-download"] [data-cy]{
  display:flex;
  align-items:center;
  gap:.5rem;
  padding:.5rem .75rem;
  margin-top:-16px;
  margin-bottom:16px;
  background:#ffffff;
  border:2px dashed #DEE2E6;          /* base gris */
  border-radius:12px;
  color:#1f2937;
  transition:border-color .2s ease, background-color .2s ease, transform .12s ease, box-shadow .2s ease;
}

/* Hover/focus en AZUL-GRIS (coherente con #DEE2E6) */
[selector="file-download"] [data-cy]:hover,
[selector="file-download"] [data-cy]:focus-within{
  border:2px solid #C7D3E3;           /* un tono sobre #DEE2E6 */
  background:#EEF5FF;                 /* azul muy claro */
  transform:translateY(-1px);
  box-shadow:0 6px 16px rgba(0,83,159,.16); /* sombra azul sutil */
  outline:none;
}

/* Botón Descargar — Azul Zurich (coherente con el resto), icono primero */
[selector="file-download"] .btn.btn-primary{
  background:#00539F !important;      /* Zurich Blue */
  border:1px solid #00539F !important;
  color:#fff !important;
  padding:.5rem .9rem;
  border-radius: 8px;
  line-height:1.1;
  display:inline-flex;
  align-items:center;
  gap:.45rem;                          /* separa icono y texto */
  text-transform:uppercase;
  letter-spacing:.02em;
  margin:0 !important;                 /* botón al inicio */
  transition:transform .12s ease, opacity .2s ease, box-shadow .2s ease;
}
[selector="file-download"] .btn.btn-primary:hover,
[selector="file-download"] .btn.btn-primary:focus{
  background:#004380 !important;
  border-color:#004380 !important;
  transform:translateY(-1px);
  box-shadow:0 6px 16px rgba(0,83,159,.30);
  opacity:.97;
}

/* ----- ÍCONO DENTRO DEL BOTÓN (blanco y forzado) ----- */
[selector="file-download"] .btn.btn-primary i,
[selector="file-download"] .btn.btn-primary .fa,
[selector="file-download"] .btn.btn-primary .fas,
[selector="file-download"] .btn.btn-primary .fa-solid{
  font-family:"Font Awesome 6 Free","Font Awesome 5 Free";
  font-weight:900;
  color:#ffffff !important;
  font-size:.95rem;
  line-height:1;
  margin-right:.1rem;                  /* fino ajuste con el gap */
  display:inline-block;
}

/* Si viene .fa-file-download, fuerza el glyph (FA5) */
[selector="file-download"] .btn.btn-primary i.fa-file-download::before{
  content:"\f56d";                     /* fa-file-download */
  font-family:"Font Awesome 5 Free";
  font-weight:900;
}
/* Fallback si usan .fa-download */
[selector="file-download"] .btn.btn-primary i.fa-download::before{
  content:"\f019";                     /* fa-download */
  font-family:"Font Awesome 5 Free";
  font-weight:900;
}

















